import React, { useState, useEffect, useContext } from 'react';
import { AuthCtx } from '../context/AuthContext';
import PageWrapper from '../components/PageWrapper';
import LoadingSpinner from '../components/LoadingSpinner';

const API_BASE = 'http://localhost:8080/api';

const Voting = () => {
  const { authToken } = useContext(AuthCtx);
  const [cands, setCands] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [voteSuccess, setVoteSuccess] = useState(false);
  const [votedUser, setVotedUser] = useState(null);

  useEffect(() => {
    const checkStatusAndFetchCands = async () => {
      setLoading(true);
      try {
        // 1. Check user profile first to see if they already voted
        const profRes = await fetch(`${API_BASE}/auth/profile`, {
          headers: { 'Authorization': `Bearer ${authToken}` }
        });

        if (profRes.ok) {
          const userData = await profRes.json();
          if (userData.has_voted) {
            setVotedUser(userData);
            setVoteSuccess(true);
            setLoading(false);
            return; // Exit early, no need to show candidates
          }
        }

        // 2. If not voted, fetch candidates
        const candRes = await fetch(`${API_BASE}/candidates`, { 
          headers: {'Authorization': `Bearer ${authToken}`} 
        });
        const candData = await candRes.json();
        setCands(candData);
        setLoading(false);
      } catch (err) {
        setLoading(false);
        setError('Failed to load voting data. Please try again later.');
      }
    };

    checkStatusAndFetchCands();
  }, [authToken]);

  const fetchUserProfile = async () => {
    try {
      const res = await fetch(`${API_BASE}/auth/profile`, {
        headers: { 'Authorization': `Bearer ${authToken}` }
      });
      if (res.ok) {
        const data = await res.json();
        setVotedUser(data);
      }
    } catch (err) {
      console.error('Failed to fetch user profile:', err);
    }
  };

  const castVote = async (id) => {
    if(!window.confirm('Are you sure? You can only vote once.')) return;
    try {
      const res = await fetch(`${API_BASE}/vote`, {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json', 
          'Authorization': `Bearer ${authToken}` 
        },
        body: JSON.stringify({candidateId: id})
      });
      if(res.ok) { 
        setVoteSuccess(true);
        await fetchUserProfile();
      } else {
        const data = await res.json();
        alert(`Error: ${data.message || 'You may have already voted.'}`);
      }
    } catch (e) {
      alert('Network error. Please try again.');
    }
  };

  if (voteSuccess && votedUser) {
    return (
      <PageWrapper>
        <section id="voting-section">
          <div className="auth-card" style={{ maxWidth: '600px', textAlign: 'center' }}>
            <div className="success-msg">✓ Vote Cast Successfully!</div>
            <h2 style={{ marginBottom: '1.5rem' }}>Your Voting Receipt</h2>
            <div className="cand-avatar">✅</div>
            <div style={{ textAlign: 'left', marginTop: '2rem', borderTop: '1px solid #eee', paddingTop: '1.5rem' }}>
              <p style={{ margin: '10px 0' }}><strong>Full Name:</strong> {votedUser.name}</p>
              <p style={{ margin: '10px 0' }}><strong>Email Address:</strong> {votedUser.email}</p>
              <p style={{ margin: '10px 0' }}><strong>Voter ID:</strong> {votedUser.voter_id}</p>
              <p style={{ margin: '10px 0' }}><strong>Account Role:</strong> {votedUser.role}</p>
              <p style={{ margin: '10px 0' }}><strong>Voting Status:</strong> <span className="success-msg" style={{ padding: '2px 8px', display: 'inline' }}>Voted</span></p>
            </div>
            <button className="btn-secondary" style={{ marginTop: '2rem', width: '100%' }} onClick={() => window.location.href='/dashboard'}>
              Go to Dashboard
            </button>
          </div>
        </section>
      </PageWrapper>
    );
  }

  return (
    <PageWrapper>
      <section id="voting-section">
        <div className="voting-header">
          <h2>Candidate Selection</h2>
          <p>Carefully select your preferred candidate. This action is final and cannot be reversed.</p>
        </div>

        {error && <p className="error-msg">{error}</p>}

        {loading ? <LoadingSpinner /> : (
          <div className="candidates-grid">
            {cands.map(c => (
              <div key={c.id} className="candidate-card">
                <div className="cand-avatar">👤</div>
                <div className="candidate-name">{c.name}</div>
                <div className="candidate-party">{c.party}</div>
                <button className="btn-primary" onClick={() => castVote(c.id)}>Vote Now</button>
              </div>
            ))}
          </div>
        )}
      </section>
    </PageWrapper>
  );
};

export default Voting;
